var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"시니어 잭슨의 신호는 여전히 잡히지 않는군요.","JPN":"シニア・ジャクソンの信号は相変わらず捉えられません。","ENG":"I still can't detect Senior Jackson's signal.","TWN":"依然無法捕捉到Senior傑森的訊號。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"강한 침식파 탓일 수도 있으니, 직접 둘러보는 편이… 음?","JPN":"強力な侵食波のせいかもしれませんから、直接見回った方が……うん？","ENG":"It might be due to the strong Corruption rays. Perhaps we should take a look around ourselv– Hmm?","TWN":"可能是因為強烈的侵蝕波，還是親自去看看比較好……嗯？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","slots":{"L":null,"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"탐지기에 아티팩트 신호가 잡히는군.","JPN":"探知機にアーティファクトの信号が感知されているな。","ENG":"The detector is picking up an Artifact.","TWN":"剛剛探測器上有神器的反應。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","slots":{"L":null,"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"위치를 특정할 순 없지만, 상당히 가까운 거리에 있는 것 같군요.","JPN":"位置を特定することはできませんが、相当近い距離にあるようです。","ENG":"I can't triangulate the location, but it seems to be close by.","TWN":"雖然無法確定具體位置，但似乎就在相當近的地方。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","slots":{"L":null,"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"탐지기의 탐측 범위를 좀 더 넓혀본다","JPN":"探知機の探測範囲をもっと広げてみる","ENG":"Increase the detector's detection range","TWN":"擴大探測器的探測範圍"},"stage":{"bg":"COUNTERSIDE_AURORA_02","slots":{"L":null,"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SAW_REAPER_NULL_QM","text":{"KOREA":"…저기요? 누구 있나요?","JPN":"……あの、誰かいますか？","ENG":"...Um? Is anyone there?","TWN":"……喂？有人在嗎？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","slots":{"L":null,"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SAW_REAPER_NULL_QM","text":{"KOREA":"여기 사람이 갇혀 있어요. 누구라도 좋으니 좀 도와주실래요?","JPN":"ここに人が閉じ込められています。誰でもいいですから、助けてくれませんか？","ENG":"There's a person trapped here. Could anyone please help me?","TWN":"這裡有人被困住了。誰都可以，能幫幫忙嗎？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","slots":{"L":null,"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"앗, 구조 요청이에요!","JPN":"あっ、救助要請です！","ENG":"Oh! It's a distress call!","TWN":"啊，是呼救訊號！"},"stage":{"bg":"COUNTERSIDE_AURORA_02","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"얼른 가보는 게…!","JPN":"早く行った方が……！","ENG":"We should go–!","TWN":"我們快走……！"},"stage":{"bg":"COUNTERSIDE_AURORA_02","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"미끼인 것 같나?","JPN":"エサだと思うか？","ENG":"Could it be bait?","TWN":"不覺得看起來像陷阱嗎？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"예, 그래 보이는군요.","JPN":"はい、そう見えますね。","ENG":"Yes, it seems so.","TWN":"是的，看起來很像。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"미끼라니… 그게 뭐죠?","JPN":"エサって……それはなんですか？","ENG":"Bait...? What do you mean?","TWN":"陷阱……你們在說什麼……？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"브레히트 양. 방금 무전은 고심도의 이면세계에서도 가장 침식파 밀도가 짙은 좌표로부터 발신됐습니다.","JPN":"ブレヒトさん。さっきの無線は高深度の裏世界でももっとも侵食波の密度が高い座標から発信されました。","ENG":"Miss Brecht. That radio was sent from coordinates where the Corruption rays are most dense, even in the hyperdepths of the Counterside.","TWN":"布萊希特，剛才的訊號是從高深度異界中侵蝕波密度最高的區域發出的。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L19_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"그런 장소에 조난된 생존자가 살아있긴 힘들 뿐더러, 저런 평온한 말투로 구조를 요청할 리 없어요.","JPN":"そんな場所に遭難した生存者が生き残っているのは難しいですし、あんな落ち着いた口調で救助を要請するはずがありません。","ENG":"Not only would it be unlikely for someone stranded there to survive, but the voice would not sound that calm.","TWN":"在那種地方遇難的倖存者很難活下來，更不可能用那種平靜的語氣求救。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그럼 저 목소린 설마…?","JPN":"じゃあ、あの声はまさか……？","ENG":"Then that voice is...?","TWN":"那麼，那個聲音難道是……？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"높은 확률로 그림자일 겁니다.","JPN":"高い確率でシャドウでしょう。","ENG":"It's highly likely to be a Shadow.","TWN":"很有可能是暗影。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"살아있는 존재를 감지하고 온갖 수단으로 자신의 영역 안까지 끌어들여 덮치는 수법이죠.","JPN":"生きている存在を感知してあらゆる手段で自分の領域の中に引き込み、襲いかかるやり方です。","ENG":"They detect living beings and use all possible means to lure them into their territory and ambush them.","TWN":"它們會感應任何活著的東西，並用各種手段將其引入自己的領域發動襲擊。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"윽- 이면세계는 다 이런 식인가요?","JPN":"うっ……裏世界ってこんな感じなんですか？","ENG":"Ngh... Is the Counterside all like this?","TWN":"呃……異界都是這種風格嗎……？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래도 확인은 해보는 편이 좋겠군. 만에 하나라는 게 있으니 말이야.","JPN":"それでも確認はした方が良さそうだな。万が一ということもあるだろう。","ENG":"But we should still go check it out. There is a one-in-a-million-chance, after all.","TWN":"但最好還是去確認一下。畢竟凡事都有個萬一。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"두 사람은 여기서 기다리게.","JPN":"2人はここで待ちたまえ。","ENG":"You two stay here.","TWN":"你們兩個人就在這裡等著吧。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"네…?","JPN":"えっ……？","ENG":"What...?","TWN":"啊……？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"잠깐, 설마 혼자 가시려고요?","JPN":"ちょっと、まさか1人で行くんですか？","ENG":"Wait. You're going alone?","TWN":"等等，你不會是想一個人去吧？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"차라리 저랑 파티마 씨가 다녀올게요.","JPN":"むしろ私とファティマさんが行ってきます。","ENG":"Fatima and I will go instead.","TWN":"不如讓我和法蒂瑪去……"},"stage":{"bg":"COUNTERSIDE_AURORA_02","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"무전의 발신지는 고심도의 이면세계에서도 침식파 계수가 가장 높은 곳일세.","JPN":"無線の発信地は高深度の裏世界でも侵食波の係数がもっとも高いところだ。","ENG":"The transmission came from a place with the highest Corruption ray values, even in the hyperdepths of the Counterside.","TWN":"發送無線電的座標在深度異界中侵蝕波係數最高的地方。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"제아무리 강한 카운터라도 그런 침식파에 노출되는 건 위험할 테니 말이야.","JPN":"いくら強いカウンターでも、それほどの侵食波に露出されるのは危険だからな。","ENG":"Even the strongest of Counters will be in danger after being exposed to that kind of Corruption ray.","TWN":"即使是再強的制裁者，暴露在那種侵蝕波中也會有危險的。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"에이, 그렇게 따지면 사장님은 더 위험하죠. 사장님은 카운터도 아니고 평범한 사람이잖아요.","JPN":"ええっ？　それを言うなら社長はもっと危険です。社長はカウンターでもないし、普通の人間じゃないですか。","ENG":"But that means that you'll be in more danger. You're just an ordinary person, Boss.","TWN":"哎呀，這麼說的話，還是老闆你更危險吧。你不是制裁者，只是個普通人啊……"},"stage":{"bg":"COUNTERSIDE_AURORA_02","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};